import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { HTMLAttributes } from 'react';
import type { AllStatuses, ColorTypes } from '../../types/status';
export type AvatarSize = 'small' | 'medium';
export type AvatarVariantType = 'square' | 'circle';
export interface AvatarProps extends HTMLAttributes<HTMLSpanElement> {
    /** Размер аватара */
    size?: AvatarSize;
    /** Форма аватара */
    variant?: AvatarVariantType;
    /**
     * Тип аватара, определяет цвет текста/ иконки и фон
     * @deprecated
     */
    type?: AllStatuses;
    /** Путь к картинке для автара*/
    src?: string;
    /** Название иконки для аватара*/
    iconName?: Icons;
    /** Инициалы для автара (рекомендуется 2 символа)*/
    letter?: string;
    /** Событие клика по компоненту*/
    onClick?: () => void;
    /** Пользовательский класс*/
    className?: string;
    /** Цвет аватара, определяет цвет текста/ иконки и фон */
    color?: ColorTypes;
    /**
     * Превращать квадратный аватар в круглый при наведении.
     * Работает только для variant="square".
     * @default false
     */
    hoverToCircle?: boolean;
    alt?: string;
}
